ICON_BASE64 = """"""

PREAMBLE_BYTES = bytes([0x08, 0x02, 0x10, 0x20, 0x22])

def make_uule(canonical_name):
    name_bytes = canonical_name.encode('utf-8')
    length_byte = struct.pack('B', len(name_bytes))
    return 'w+' + base64.b64encode(PREAMBLE_BYTES + length_byte + name_bytes).decode('ascii')

def extract_icon():
    path = os.path.join(tempfile.gettempdir(), 'google_uule.ico')
    if not os.path.exists(path):
        with open(path, 'wb') as f:
            f.write(base64.b64decode(ICON_BASE64))
    return path

class GoogleUuleApp(tk.Tk):
    def __init__(self):
        super().__init__()
        self.title("Google Uule")
        self.configure(bg='#f5f0eb')
        self.resizable(False, False)

        try:
            ico = extract_icon()
            self.iconbitmap(ico)
        except:
            pass

        try:
            ctypes.windll.shell32.SetCurrentProcessExplicitAppUserModelID('webadhere.googleuule.1')
        except:
            pass

        self.provinces = TURKEY_DATA
        self.province_map = {p['name']: p for p in self.provinces}
        self.province_names = [p['name'] for p in self.provinces]

        # Style
        style = ttk.Style()
        style.theme_use('clam')
        bg, fg, sel_bg = '#f5f0eb', '#3d3d3d', '#e8ddd0'
        entry_bg, entry_fg = '#ffffff', '#2d2d2d'
        accent, accent_hover = '#d4a373', '#c68f5c'
        style.configure('.', background=bg, foreground=fg, fieldbackground=entry_bg, arrowcolor='#8a8a8a')
        style.configure('TLabel', background=bg, foreground=fg, font=('Segoe UI', 10))
        style.configure('TCombobox', background=entry_bg, foreground=entry_fg, fieldbackground=entry_bg, selectbackground=sel_bg, selectforeground=fg, font=('Segoe UI', 9), padding=4, bordercolor='#e0d5c8', lightcolor='#e0d5c8', darkcolor='#e0d5c8')
        style.map('TCombobox', fieldbackground=[('readonly', entry_bg)], foreground=[('readonly', entry_fg)])
        style.configure('TFrame', background=bg)
        style.configure('Header.TLabel', background=bg, foreground='#8b6f5c', font=('Segoe UI', 16, 'bold'))
        style.configure('SubHeader.TLabel', background=bg, foreground='#a0806a', font=('Segoe UI', 9))
        style.configure('Footer.TLabel', background=bg, foreground='#c0b0a0', font=('Segoe UI', 8))
        style.configure('Raw.TEntry', fieldbackground='#faf8f5', foreground='#6b8e6b', font=('Consolas', 9), padding=4, bordercolor='#e0d5c8')
        style.configure('Full.TEntry', fieldbackground='#faf8f5', foreground='#8b6f5c', font=('Consolas', 9), padding=4, bordercolor='#e0d5c8')

        self.geometry(f'560x400+{int((self.winfo_screenwidth()-560)/2)}+{int((self.winfo_screenheight()-400)/2)}')

        main = tk.Frame(self, bg='#f5f0eb', padx=28, pady=24)
        main.pack(fill=tk.BOTH, expand=True)

        ttk.Label(main, text="☰  UULE Code Generator", style='Header.TLabel').pack(pady=(0, 4), anchor='w')
        ttk.Label(main, text="Konum seçerek Google UULE kodu oluşturun", style='SubHeader.TLabel').pack(pady=(0, 18), anchor='w')

        # Province
        fr1 = tk.Frame(main, bg='#f5f0eb')
        fr1.pack(fill=tk.X, pady=4)
        ttk.Label(fr1, text="İl", width=8).pack(side=tk.LEFT)
        self.province_var = tk.StringVar()
        self.province_cb = ttk.Combobox(fr1, textvariable=self.province_var, values=self.province_names, state='readonly')
        self.province_cb.pack(side=tk.LEFT, fill=tk.X, expand=True)
        self.province_cb.bind('<<ComboboxSelected>>', self.on_province_change)

        # District
        fr2 = tk.Frame(main, bg='#f5f0eb')
        fr2.pack(fill=tk.X, pady=4)
        ttk.Label(fr2, text="İlçe", width=8).pack(side=tk.LEFT)
        self.district_var = tk.StringVar()
        self.district_cb = ttk.Combobox(fr2, textvariable=self.district_var, state='readonly')
        self.district_cb.pack(side=tk.LEFT, fill=tk.X, expand=True)
        self.district_cb.bind('<<ComboboxSelected>>', self.on_district_change)

        # Separator
        ttk.Separator(main).pack(fill=tk.X, pady=(16, 12))

        # UULE output - raw
        fr3 = tk.Frame(main, bg='#f5f0eb')
        fr3.pack(fill=tk.X, pady=3)
        ttk.Label(fr3, text="UULE", width=8).pack(side=tk.LEFT)
        self.uule_var = tk.StringVar()
        self.uule_entry = ttk.Entry(fr3, textvariable=self.uule_var, style='Raw.TEntry')
        self.uule_entry.pack(side=tk.LEFT, fill=tk.X, expand=True)

        # UULE output - with &uule=
        fr4 = tk.Frame(main, bg='#f5f0eb')
        fr4.pack(fill=tk.X, pady=3)
        ttk.Label(fr4, text="&uule=", width=8).pack(side=tk.LEFT)
        self.uule_full_var = tk.StringVar()
        self.uule_full_entry = ttk.Entry(fr4, textvariable=self.uule_full_var, style='Full.TEntry')
        self.uule_full_entry.pack(side=tk.LEFT, fill=tk.X, expand=True)

        # Buttons
        btn_fr = tk.Frame(main, bg='#f5f0eb')
        btn_fr.pack(pady=(18, 0))
        tk.Button(btn_fr, text="Kopyala", command=self.copy_uule, font=('Segoe UI', 10, 'bold'), bg='#d4a373', fg='white', padx=28, pady=6, bd=0, cursor='hand2', activebackground='#c68f5c').pack(side=tk.LEFT, padx=5)
        tk.Button(btn_fr, text="Temizle", command=self.clear_all, font=('Segoe UI', 9), bg='#ddd5cc', fg='#6b5b4c', padx=28, pady=6, bd=0, cursor='hand2', activebackground='#ccc3b8').pack(side=tk.LEFT, padx=5)

        # Footer
        ttk.Label(main, text="WebAdHere Software", style='Footer.TLabel').pack(side=tk.BOTTOM, anchor='se', pady=(8, 0))

    def on_province_change(self, event=None):
        prov = self.province_map.get(self.province_var.get())
        if not prov: return
        self.district_cb['values'] = [d['name'] for d in prov['districts']]
        self.district_cb.set('')
        self.uule_var.set('')
        self.uule_full_var.set('')

    def on_district_change(self, event=None):
        prov = self.province_map.get(self.province_var.get())
        dist = self.district_var.get()
        if not prov or not dist: return
        if dist == prov['name']:
            c = prov['canonical']
        else:
            c = next((d['canonical'] for d in prov['districts'] if d['name'] == dist), None)
        if c:
            raw = make_uule(c)
            self.uule_var.set(raw)
            self.uule_full_var.set('&uule=' + raw)

    def copy_uule(self):
        val = self.uule_full_var.get()
        if not val:
            messagebox.showwarning("Uyarı", "Önce bir konum seçin.")
            return
        self.clipboard_clear()
        self.clipboard_append(val)
        messagebox.showinfo("Kopyalandı", "&uule=... panoya kopyalandı!")

    def clear_all(self):
        self.province_cb.set('')
        self.district_cb['values'] = []
        self.district_cb.set('')
        self.uule_var.set('')
        self.uule_full_var.set('')

if __name__ == '__main__':
    GoogleUuleApp().mainloop()
